import com.smartquiz.config.DBConnection; import java.sql.*; public class DebugQuizzes { public static void main(String[] args) throws Exception { try (Connection conn = DBConnection.getConnection()) { int studentId = -1; try (PreparedStatement ps = conn.prepareStatement("SELECT id FROM users WHERE email = ?")) { ps.setString(1, "test@student.com"); ResultSet rs = ps.executeQuery(); if (rs.next()) studentId = rs.getInt("id"); } System.out.println("Student ID: " + studentId); String sql = "SELECT DISTINCT q.*, COALESCE(c.name, \"General\") as class_name " + "FROM quizzes q " + "LEFT JOIN classes c ON q.class_id = c.id " + "LEFT JOIN enrollments e ON q.class_id = e.class_id AND e.student_id = ? " + "LEFT JOIN attempts a ON q.id = a.quiz_id AND a.student_id = ? " + "WHERE q.is_published = TRUE AND a.id IS NULL " + "AND (q.class_id = 0 OR q.class_id IS NULL OR e.id IS NOT NULL)"; try (PreparedStatement ps = conn.prepareStatement(sql)) { ps.setInt(1, studentId); ps.setInt(2, studentId); ResultSet rs = ps.executeQuery(); while (rs.next()) { System.out.println("Quiz found: " + rs.getString("title") + " (Class: " + rs.getString("class_name") + ")"); } } } } }
